blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz najważniejsze <strong>quantifiers</strong>: <strong>much, many, a lot of, few, little</strong> i zobaczysz, jak łączyć je z rzeczownikami policzalnymi oraz niepoliczalnymi.",
    "rules": [
        {
            "label": "Many",
            "color": "emerald",
            "text": "<strong>Many</strong> łączymy z rzeczownikami policzalnymi w liczbie mnogiej:",
            "example": "many books, many friends, many ideas"
        },
        {
            "label": "Much",
            "color": "blue",
            "text": "<strong>Much</strong> łączymy z rzeczownikami niepoliczalnymi:",
            "example": "much time, much money, much water"
        },
        {
            "label": "A lot of",
            "color": "amber",
            "text": "<strong>A lot of</strong> działa z obiema grupami rzeczowników i brzmi naturalnie w twierdzeniach:",
            "example": "a lot of books, a lot of time"
        }
    ]
}

{
    "title": "1. Czym są quantifiers?",
    "intro": "To słowa, które pomagają określić ilość:",
    "items": [
        {
            "label": "Much / Many",
            "title": "Dużo",
            "subtitle": "Many łączy się z rzeczownikami policzalnymi, a much z niepoliczalnymi"
        },
        {
            "label": "A lot of",
            "title": "Dużo w neutralny sposób",
            "subtitle": "Uniwersalna opcja dla obu typów rzeczowników"
        },
        {
            "label": "Few / Little",
            "title": "Mało",
            "subtitle": "Few dotyczy policzalnych, a little / little dotyczy niepoliczalnych"
        }
    ]
}

{
    "title": "2. Many z rzeczownikami policzalnymi",
    "sections": [
        {
            "label": "Zasada",
            "color": "emerald",
            "description": "<strong>Many</strong> używamy z <strong>rzeczownikami policzalnymi w liczbie mnogiej</strong>.",
            "examples": [
                {
                    "en": "many books",
                    "ua": "wiele książek"
                },
                {
                    "en": "many friends",
                    "ua": "wielu przyjaciół"
                },
                {
                    "en": "many people",
                    "ua": "wiele osób"
                },
                {
                    "en": "many ideas",
                    "ua": "wiele pomysłów"
                }
            ]
        },
        {
            "label": "W zdaniach",
            "color": "sky",
            "description": "<strong>Many</strong> często pojawia się w pytaniach i przeczeniach.",
            "examples": [
                {
                    "en": "How many books do you have?",
                    "ua": "Ile masz książek?"
                },
                {
                    "en": "I don't have many friends here.",
                    "ua": "Nie mam tu wielu przyjaciół."
                },
                {
                    "en": "There are many people in the park.",
                    "ua": "W parku jest wiele osób."
                },
                {
                    "en": "Do you have many questions?",
                    "ua": "Masz dużo pytań?"
                }
            ]
        },
        {
            "label": "Naturalne użycie",
            "color": "amber",
            "description": "W zwykłych zdaniach twierdzących <strong>a lot of</strong> bywa naturalniejsze niż <strong>many</strong>.",
            "examples": [
                {
                    "en": "How many friends do you have?",
                    "ua": "typowe pytanie"
                },
                {
                    "en": "I don't have many books.",
                    "ua": "typowe przeczenie"
                },
                {
                    "en": "I have a lot of books.",
                    "ua": "bardziej naturalne twierdzenie"
                }
            ],
            "note": "Many jest poprawne, ale w potocznym twierdzeniu często wybiera się a lot of."
        }
    ]
}

{
    "title": "3. Much z rzeczownikami niepoliczalnymi",
    "sections": [
        {
            "label": "Zasada",
            "color": "blue",
            "description": "<strong>Much</strong> łączymy z <strong>rzeczownikami niepoliczalnymi</strong>.",
            "examples": [
                {
                    "en": "much time",
                    "ua": "dużo czasu"
                },
                {
                    "en": "much money",
                    "ua": "dużo pieniędzy"
                },
                {
                    "en": "much water",
                    "ua": "dużo wody"
                },
                {
                    "en": "much information",
                    "ua": "dużo informacji"
                }
            ]
        },
        {
            "label": "W zdaniach",
            "color": "sky",
            "description": "Tak jak many, <strong>much</strong> najczęściej pojawia się w pytaniach i przeczeniach.",
            "examples": [
                {
                    "en": "How much money do you need?",
                    "ua": "Ile pieniędzy potrzebujesz?"
                },
                {
                    "en": "I don't have much time today.",
                    "ua": "Nie mam dziś zbyt wiele czasu."
                },
                {
                    "en": "There isn't much water left.",
                    "ua": "Nie zostało dużo wody."
                },
                {
                    "en": "Do you have much experience?",
                    "ua": "Masz duże doświadczenie?"
                }
            ]
        },
        {
            "label": "Naturalne użycie",
            "color": "amber",
            "description": "W twierdzeniach bardzo często lepiej brzmi <strong>a lot of</strong> niż <strong>much</strong>.",
            "examples": [
                {
                    "en": "How much time do you have?",
                    "ua": "typowe pytanie"
                },
                {
                    "en": "I don't have much money.",
                    "ua": "typowe przeczenie"
                },
                {
                    "en": "I have a lot of money.",
                    "ua": "bardziej naturalne twierdzenie"
                }
            ],
            "note": "Much w twierdzeniach brzmi bardziej formalnie lub książkowo."
        }
    ]
}

{
    "title": "4. A lot of / lots of jako opcja uniwersalna",
    "sections": [
        {
            "label": "Dla obu typów rzeczowników",
            "color": "purple",
            "description": "<strong>A lot of</strong> i <strong>lots of</strong> łączą się zarówno z rzeczownikami policzalnymi, jak i niepoliczalnymi.",
            "examples": [
                {
                    "en": "a lot of books (countable)",
                    "ua": "dużo książek"
                },
                {
                    "en": "a lot of time (uncountable)",
                    "ua": "dużo czasu"
                },
                {
                    "en": "lots of friends",
                    "ua": "mnóstwo przyjaciół"
                },
                {
                    "en": "lots of money",
                    "ua": "mnóstwo pieniędzy"
                }
            ]
        },
        {
            "label": "Najbardziej naturalne w twierdzeniach",
            "color": "emerald",
            "description": "W zwykłych zdaniach twierdzących <strong>a lot of</strong> bardzo często brzmi najlepiej.",
            "examples": [
                {
                    "en": "I have a lot of friends.",
                    "ua": "Mam wielu przyjaciół."
                },
                {
                    "en": "She has a lot of time.",
                    "ua": "Ona ma dużo czasu."
                },
                {
                    "en": "We read a lot of books.",
                    "ua": "Czytamy dużo książek."
                },
                {
                    "en": "They drink a lot of water.",
                    "ua": "Piją dużo wody."
                }
            ]
        },
        {
            "label": "Lots of jest bardziej potoczne",
            "color": "sky",
            "description": "<strong>Lots of</strong> jest trochę bardziej swobodne niż <strong>a lot of</strong>.",
            "examples": [
                {
                    "en": "I have lots of work to do.",
                    "ua": "Mam mnóstwo pracy."
                },
                {
                    "en": "There are lots of people here.",
                    "ua": "Jest tu mnóstwo ludzi."
                }
            ],
            "note": "A lot of brzmi neutralnie, a lots of jest bardziej rozmowne."
        }
    ]
}

{
    "title": "5. Few i a few z rzeczownikami policzalnymi",
    "sections": [
        {
            "label": "Few = mało, za mało",
            "color": "rose",
            "description": "<strong>Few</strong> ma zwykle <strong>negatywny wydźwięk</strong>: czegoś jest mało i to nie wystarcza.",
            "examples": [
                {
                    "en": "I have few friends here.",
                    "ua": "Mam tu mało przyjaciół."
                },
                {
                    "en": "Few people know about it.",
                    "ua": "Mało osób o tym wie."
                },
                {
                    "en": "There are few books on the shelf.",
                    "ua": "Na półce jest niewiele książek."
                }
            ]
        },
        {
            "label": "A few = kilka, wystarczająco",
            "color": "emerald",
            "description": "<strong>A few</strong> ma bardziej <strong>pozytywny lub neutralny</strong> wydźwięk: czegoś jest trochę i to wystarcza.",
            "examples": [
                {
                    "en": "I have a few friends here.",
                    "ua": "Mam tu kilku przyjaciół."
                },
                {
                    "en": "A few people know about it.",
                    "ua": "Kilka osób o tym wie."
                },
                {
                    "en": "I need a few minutes.",
                    "ua": "Potrzebuję kilku minut."
                }
            ]
        },
        {
            "label": "Artykuł zmienia znaczenie",
            "color": "amber",
            "description": "Samo <strong>few</strong> i <strong>a few</strong> nie znaczą tego samego.",
            "examples": [
                {
                    "en": "Few people came.",
                    "ua": "Przyszło mało osób."
                },
                {
                    "en": "A few people came.",
                    "ua": "Przyszło kilka osób."
                }
            ],
            "note": "Few sugeruje niedobór, a a few sugeruje, że ilość jest wystarczająca."
        }
    ]
}

{
    "title": "6. Little i a little z rzeczownikami niepoliczalnymi",
    "sections": [
        {
            "label": "Little = mało, za mało",
            "color": "rose",
            "description": "<strong>Little</strong> ma negatywny wydźwięk i oznacza, że czegoś jest <strong>za mało</strong>.",
            "examples": [
                {
                    "en": "I have little time.",
                    "ua": "Mam mało czasu."
                },
                {
                    "en": "There is little water left.",
                    "ua": "Zostało mało wody."
                },
                {
                    "en": "We have little information.",
                    "ua": "Mamy mało informacji."
                }
            ]
        },
        {
            "label": "A little = trochę, wystarczająco",
            "color": "emerald",
            "description": "<strong>A little</strong> oznacza, że czegoś jest trochę i zwykle to wystarcza.",
            "examples": [
                {
                    "en": "I have a little time.",
                    "ua": "Mam trochę czasu."
                },
                {
                    "en": "There is a little water left.",
                    "ua": "Zostało jeszcze trochę wody."
                },
                {
                    "en": "I need a little help.",
                    "ua": "Potrzebuję odrobiny pomocy."
                }
            ]
        },
        {
            "label": "Artykuł znów zmienia znaczenie",
            "color": "amber",
            "description": "Podobnie jak przy few, samo <strong>little</strong> i <strong>a little</strong> niosą inny sens.",
            "examples": [
                {
                    "en": "There is little hope.",
                    "ua": "Jest mało nadziei."
                },
                {
                    "en": "There is a little hope.",
                    "ua": "Jest jeszcze trochę nadziei."
                }
            ],
            "note": "Little brzmi bardziej pesymistycznie niż a little."
        }
    ]
}

{
    "title": "7. Jak szybko wybrać quantifier",
    "sections": [
        {
            "label": "Rzeczowniki policzalne",
            "color": "emerald",
            "description": "Przy liczbie mnogiej rzeczowników policzalnych najczęściej wybieramy <strong>many, a few, few</strong>.",
            "examples": [
                {
                    "en": "many books / a few friends / few mistakes",
                    "ua": "typowe połączenia z rzeczownikami policzalnymi"
                }
            ]
        },
        {
            "label": "Rzeczowniki niepoliczalne",
            "color": "blue",
            "description": "Przy rzeczownikach niepoliczalnych używamy zwykle <strong>much, a little, little</strong>.",
            "examples": [
                {
                    "en": "much time / a little water / little hope",
                    "ua": "typowe połączenia z rzeczownikami niepoliczalnymi"
                }
            ]
        },
        {
            "label": "Opcja neutralna",
            "color": "amber",
            "description": "Jeśli nie chcesz brzmieć zbyt formalnie, <strong>a lot of</strong> jest bezpiecznym wyborem dla obu grup.",
            "examples": [
                {
                    "en": "a lot of books / a lot of work",
                    "ua": "uniwersalna opcja w twierdzeniach"
                }
            ]
        }
    ]
}

{
    "title": "8. Tabela porównawcza",
    "intro": "Najważniejsze quantifiers i ich użycie:",
    "rows": [
        {
            "en": "Many",
            "ua": "Dużo (policzalne)",
            "note": "many books, many friends; częste w pytaniach i przeczeniach"
        },
        {
            "en": "Much",
            "ua": "Dużo (niepoliczalne)",
            "note": "much time, much money; częste w pytaniach i przeczeniach"
        },
        {
            "en": "A lot of / lots of",
            "ua": "Dużo (oba typy)",
            "note": "a lot of books / time; bardzo naturalne w twierdzeniach"
        },
        {
            "en": "Few",
            "ua": "Mało (policzalne, negatywnie)",
            "note": "few people = za mało"
        },
        {
            "en": "A few",
            "ua": "Kilka (policzalne, neutralnie / pozytywnie)",
            "note": "a few friends = wystarczająco"
        },
        {
            "en": "Little",
            "ua": "Mało (niepoliczalne, negatywnie)",
            "note": "little time = za mało"
        },
        {
            "en": "A little",
            "ua": "Trochę (niepoliczalne, neutralnie / pozytywnie)",
            "note": "a little water = wystarczająco"
        }
    ],
    "warning": "Przedimek <strong>a</strong> przed few i little wyraźnie zmienia znaczenie."
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Much z rzeczownikiem policzalnym.",
            "wrong": "I have much books.",
            "right": "✅ <span class=\"font-mono\">I have many books. / I have a lot of books.<\/span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Many z rzeczownikiem niepoliczalnym.",
            "wrong": "I don't have many time.",
            "right": "✅ <span class=\"font-mono\">I don't have much time.<\/span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie little i a little.",
            "wrong": "I have little time. (gdy chcesz powiedzieć, że trochę czasu jednak jest)",
            "right": "✅ <span class=\"font-mono\">I have a little time.<\/span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Many / much w twierdzeniu, gdy naturalniejsze jest a lot of.",
            "wrong": "I have many friends.",
            "right": "✅ <span class=\"font-mono\">I have a lot of friends.<\/span>"
        }
    ]
}

{
    "title": "11. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawny quantifier",
    "select_intro": "Wybierz słowo, które najlepiej pasuje do zdania.",
    "selects": [
        {
            "label": "I don't have ___ time. (much / many)",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "How ___ books do you have? (much / many)",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "She has ___ friends. (a lot of / much)",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "There is ___ water left. (few / little)",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "Pierwsza opcja",
        "Druga opcja"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij zdania",
    "input_intro": "Wpisz many, much albo a lot of.",
    "inputs": [
        {
            "before": "I have ___ work to do.",
            "after": "→"
        },
        {
            "before": "How ___ money do you need?",
            "after": "→"
        },
        {
            "before": "There are ___ people here.",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd związany z quantifierem.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I have much books.",
            "example_target": "I have many books. / I have a lot of books."
        },
        {
            "original": "1. She doesn't have many time.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "2. There are much people in the room.",
            "placeholder": "Popraw zdanie"
        }
    ]
}

{
    "title": "Inne strony z tej kategorii",
    "items": [
        {
            "label": "Quantifiers — much, many, few, little",
            "current": true
        },
        {
            "label": "Articles — A / An / The",
            "current": false
        },
        {
            "label": "Zero Article — brak przedimka",
            "current": false
        },
        {
            "label": "Plural Nouns — liczba mnoga rzeczowników",
            "current": false
        }
    ]
}
